    int alignedSize = DIVANDRND(pixels, THREADS) * THREADS;

    unsigned char *cl_d_src = nullptr;
    cudaMalloc((void **)&cl_d_src, pixels);
    cudaMemcpy(cl_d_src, h_src, pixels, cudaMemcpyHostToDevice);

    size_t globalWorkSize = alignedSize / 9;
    assert(alignedSize % (THREADS * 3) == 0);

    cuda_c_CopySrcToComponent(d_c, cl_d_src, pixels, (int)globalWorkSize);

    std::cout << "bwToComponent has finished\n";
    cudaFree(cl_d_src);
}

void launchFDWT53Kernel(int WIN_SX, int WIN_SY, int *in, int *out, int sx, int sy)
{
    const int steps = (sy / (15 * WIN_SY)) + ((sy % (15 * WIN_SY)) ? 1 : 0);
    int gx = (sx / WIN_SX) + ((sx % WIN_SX) ? 1 : 0);
    int gy = (sy / (WIN_SY * steps)) + ((sy % (WIN_SY * steps)) ? 1 : 0);

    printf("sliding steps = %d , gx = %d , gy = %d \n", steps, gx, gy);
    cuda_cl_fdwt53Kernel(in, out, sx, sy, steps, WIN_SX, WIN_SY, gx, gy);
    printf("kl_fdwt53Kernel in launchFDW53Kernel has finished\n");
}

void memCopy(int *dest, int *src, const size_t sx, const size_t sy)
{
    cudaMemcpy(dest, src, sx * sy * sizeof(int), cudaMemcpyDeviceToDevice);
}

void fdwt53(int *in, int *out, int sizeX, int sizeY, int levels)
{
    if (sizeX >= 960) {
        launchFDWT53Kernel(192, 8, in, out, sizeX, sizeY);
    } else if (sizeX >= 480) {
        launchFDWT53Kernel(128, 8, in, out, sizeX, sizeY);
    } else {
        launchFDWT53Kernel(64, 8, in, out, sizeX, sizeY);
    }

    if (levels > 1) {
        const int llSizeX = (sizeX / 2) + ((sizeX % 2) ? 1 : 0);
        const int llSizeY = (sizeY / 2) + ((sizeY % 2) ? 1 : 0);
        memCopy(in, out, llSizeX, llSizeY);
        fdwt53(in, out, llSizeX, llSizeY, levels - 1);
    }
}

int nStage2dDWT(int *in, int *out, int *backup, int pixWidth, int pixHeight, int stages, bool forward)
{
    printf("\n*** %d stages of 2D forward DWT:\n", stages);
    if (forward) fdwt53(in, out, pixWidth, pixHeight, stages);
    return 0;
}

void samplesToChar(unsigned char *dst, int *src, int samplesNum)
{
    for (int i = 0; i < samplesNum; i++) {
        int r = src[i] + 128;
        if (r > 255) r = 255;
        if (r < 0)   r = 0;
        dst[i] = (unsigned char)r;
    }
}

int writeLinear(int *component, int pixWidth, int pixHeight, const char *filename, const char *suffix)
{
    int samplesNum = pixWidth * pixHeight;
    int size = samplesNum * sizeof(int);

    int *gpu_output = (int *)malloc(size);
    memset(gpu_output, 0, size);
    unsigned char *result = (unsigned char *)malloc(samplesNum);

    cudaMemcpy(gpu_output, component, size, cudaMemcpyDeviceToHost);
    samplesToChar(result, gpu_output, samplesNum);

    std::string outfile = std::string(filename) + suffix;
    int i = open(outfile.c_str(), O_CREAT | O_WRONLY, 0644);
    if (i == -1) {
        error(0, errno, "cannot access %s", outfile.c_str());
        return -1;
    }
    printf("\nWriting to %s (%d x %d)\n", outfile.c_str(), pixWidth, pixHeight);
    write(i, result, samplesNum);
    close(i);

    free(gpu_output);
    free(result);
    return 0;
}

int writeNStage2DDWT(int *component, int pixWidth, int pixHeight, int stages, const char *filename, const char *suffix)
{
    struct band { int dimX; int dimY; };
    struct dimensions { band LL; band HL; band LH; band HH; };

    int samplesNum = pixWidth * pixHeight;
    dimensions *bandDims = (dimensions *)malloc(stages * sizeof(dimensions));

    bandDims[0].LL.dimX = DIVANDRND(pixWidth, 2);
    bandDims[0].LL.dimY = DIVANDRND(pixHeight, 2);
    bandDims[0].HL.dimX = pixWidth - bandDims[0].LL.dimX;
    bandDims[0].HL.dimY = bandDims[0].LL.dimY;
    bandDims[0].LH.dimX = bandDims[0].LL.dimX;
    bandDims[0].LH.dimY = pixHeight - bandDims[0].LL.dimY;
    bandDims[0].HH.dimX = bandDims[0].HL.dimX;
    bandDims[0].HH.dimY = bandDims[0].LH.dimY;

    for (int i = 1; i < stages; i++) {
        bandDims[i].LL.dimX = DIVANDRND(bandDims[i - 1].LL.dimX, 2);
        bandDims[i].LL.dimY = DIVANDRND(bandDims[i - 1].LL.dimY, 2);
        bandDims[i].HL.dimX = bandDims[i - 1].LL.dimX - bandDims[i].LL.dimX;
        bandDims[i].HL.dimY = bandDims[i].LL.dimY;
        bandDims[i].LH.dimX = bandDims[i].LL.dimX;
        bandDims[i].LH.dimY = bandDims[i - 1].LL.dimY - bandDims[i].LL.dimY;
        bandDims[i].HH.dimX = bandDims[i].HL.dimX;
        bandDims[i].HH.dimY = bandDims[i].LH.dimY;
    }

    int size = samplesNum * sizeof(int);
    int *src = (int *)malloc(size);
    memset(src, 0, size);
    int *dst = (int *)malloc(size);
    memset(dst, 0, size);
    unsigned char *result = (unsigned char *)malloc(samplesNum);

    cudaMemcpy(src, component, size, cudaMemcpyDeviceToHost);

    size = bandDims[stages - 1].LL.dimX * sizeof(int);
    for (int i = 0; i < bandDims[stages - 1].LL.dimY; i++) {
        memcpy(dst + i * pixWidth, src + i * bandDims[stages - 1].LL.dimX, size);
    }

    for (int s = stages - 1; s >= 0; s--) {
        int offset, yOffset;

        size = bandDims[s].HL.dimX * sizeof(int);
        offset = bandDims[s].LL.dimX * bandDims[s].LL.dimY;
        for (int i = 0; i < bandDims[s].HL.dimY; i++) {
            memcpy(dst + i * pixWidth + bandDims[s].LL.dimX, src + offset + i * bandDims[s].HL.dimX, size);
        }

        size = bandDims[s].LH.dimX * sizeof(int);
        offset += bandDims[s].HL.dimX * bandDims[s].HL.dimY;
        yOffset = bandDims[s].LL.dimY;
        for (int i = 0; i < bandDims[s].HL.dimY; i++) {
            memcpy(dst + (yOffset + i) * pixWidth, src + offset + i * bandDims[s].LH.dimX, size);
        }

        size = bandDims[s].HH.dimX * sizeof(int);
        offset += bandDims[s].LH.dimX * bandDims[s].LH.dimY;
        yOffset = bandDims[s].HL.dimY;
        for (int i = 0; i < bandDims[s].HH.dimY; i++) {
            memcpy(dst + (yOffset + i) * pixWidth + bandDims[s].LH.dimX, src + offset + i * bandDims[s].HH.dimX, size);
        }
    }

    samplesToChar(result, dst, samplesNum);

    std::string outfile = std::string(filename) + suffix;
    int i = open(outfile.c_str(), O_CREAT | O_WRONLY, 0644);
    if (i == -1) {
        error(0, errno, "cannot access %s", outfile.c_str());
        return -1;
    }

    printf("\nWriting to %s (%d x %d)\n", outfile.c_str(), pixWidth, pixHeight);
    write(i, result, samplesNum);
    close(i);

    free(src);
    free(dst);
    free(result);
    free(bandDims);
    return 0;
}

template <typename T>
void processDWT(struct dwt *d, int forward, int writeVisual)
{
    int componentSize = d->pixWidth * d->pixHeight * sizeof(T);
    T *temp = (T *)malloc(componentSize);
    memset(temp, 0, componentSize);

    T *cl_c_r_out = nullptr;
    T *cl_backup = nullptr;
    cudaMalloc((void **)&cl_c_r_out, componentSize);
    cudaMemcpy(cl_c_r_out, temp, componentSize, cudaMemcpyHostToDevice);
    cudaMalloc((void **)&cl_backup, componentSize);
    cudaMemcpy(cl_backup, temp, componentSize, cudaMemcpyHostToDevice);

    if (d->components == 3) {
        T *cl_c_g_out = nullptr, *cl_c_b_out = nullptr;
        T *cl_c_r = nullptr, *cl_c_g = nullptr, *cl_c_b = nullptr;

        cudaMalloc((void **)&cl_c_g_out, componentSize);
        cudaMemcpy(cl_c_g_out, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc((void **)&cl_c_b_out, componentSize);
        cudaMemcpy(cl_c_b_out, temp, componentSize, cudaMemcpyHostToDevice);

        cudaMalloc((void **)&cl_c_r, componentSize);
        cudaMemcpy(cl_c_r, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc((void **)&cl_c_g, componentSize);
        cudaMemcpy(cl_c_g, temp, componentSize, cudaMemcpyHostToDevice);
        cudaMalloc((void **)&cl_c_b, componentSize);
        cudaMemcpy(cl_c_b, temp, componentSize, cudaMemcpyHostToDevice);

        rgbToComponents(reinterpret_cast<int *>(cl_c_r), reinterpret_cast<int *>(cl_c_g), reinterpret_cast<int *>(cl_c_b), d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWT(reinterpret_cast<int *>(cl_c_r), reinterpret_cast<int *>(cl_c_r_out), reinterpret_cast<int *>(cl_backup), d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWT(reinterpret_cast<int *>(cl_c_g), reinterpret_cast<int *>(cl_c_g_out), reinterpret_cast<int *>(cl_backup), d->pixWidth, d->pixHeight, d->dwtLvls, forward);
        nStage2dDWT(reinterpret_cast<int *>(cl_c_b), reinterpret_cast<int *>(cl_c_b_out), reinterpret_cast<int *>(cl_backup), d->pixWidth, d->pixHeight, d->dwtLvls, forward);

#ifdef OUTPUT
        if (writeVisual) {
            writeNStage2DDWT(reinterpret_cast<int *>(cl_c_r_out), d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
            writeNStage2DDWT(reinterpret_cast<int *>(cl_c_g_out), d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".g");
            writeNStage2DDWT(reinterpret_cast<int *>(cl_c_b_out), d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".b");
        } else {
            writeLinear(reinterpret_cast<int *>(cl_c_r_out), d->pixWidth, d->pixHeight, d->outFilename, ".r");
            writeLinear(reinterpret_cast<int *>(cl_c_g_out), d->pixWidth, d->pixHeight, d->outFilename, ".g");
            writeLinear(reinterpret_cast<int *>(cl_c_b_out), d->pixWidth, d->pixHeight, d->outFilename, ".b");
        }
#endif

        cudaFree(cl_c_r);
        cudaFree(cl_c_g);
        cudaFree(cl_c_b);
        cudaFree(cl_c_g_out);
        cudaFree(cl_c_b_out);
    } else if (d->components == 1) {
        T *cl_c_r = nullptr;
        cudaMalloc((void **)&cl_c_r, componentSize);
        cudaMemcpy(cl_c_r, temp, componentSize, cudaMemcpyHostToDevice);

        bwToComponent(reinterpret_cast<int *>(cl_c_r), d->srcImg, d->pixWidth, d->pixHeight);

        nStage2dDWT(reinterpret_cast<int *>(cl_c_r), reinterpret_cast<int *>(cl_c_r_out), reinterpret_cast<int *>(cl_backup), d->pixWidth, d->pixHeight, d->dwtLvls, forward);

        if (writeVisual) {
            writeNStage2DDWT(reinterpret_cast<int *>(cl_c_r_out), d->pixWidth, d->pixHeight, d->dwtLvls, d->outFilename, ".r");
        } else {
            writeLinear(reinterpret_cast<int *>(cl_c_r_out), d->pixWidth, d->pixHeight, d->outFilename, ".r");
        }

        cudaFree(cl_c_r);
    }

    free(temp);
    cudaFree(cl_c_r_out);
    cudaFree(cl_backup);
}

int main(int argc, char **argv)
{
    int optindex = 0;
    char ch;
    struct option longopts[] = {
        {"dimension", required_argument, 0, 'D'},
        {"components", required_argument, 0, 'c'},
        {"depth", required_argument, 0, 'b'},
        {"level", required_argument, 0, 'l'},
        {"device", required_argument, 0, 'd'},
        {"platform", required_argument, 0, 'p'},
        {"input-dir", required_argument, 0, 'i'},
        {"forward", no_argument, 0, 'f'},
        {"reverse", no_argument, 0, 'r'},
        {"97", no_argument, 0, '9'},
        {"53", no_argument, 0, '5'},
        {"write-visual", no_argument, 0, 'w'},
        {"help", no_argument, 0, 'h'}
    };

    int pixWidth = 0, pixHeight = 0, compCount = 3, bitDepth = 8, dwtLvls = 3;
    int forward = 1, dwt97 = 0, writeVisual = 0;
    char input_dir[100] = {"."};
    char *pos;

    while ((ch = getopt_long(argc, argv, "d:p:c:b:l:i:D:fr95wh", longopts, &optindex)) != -1) {
        switch (ch) {
            case 'D':
                pixWidth = atoi(optarg);
                pos = strstr(optarg, "x");
                if (pos == NULL || pixWidth == 0 || (strlen(pos) >= strlen(optarg))) { usage(); return -1; }
                pixHeight = atoi(pos + 1);
                break;
            case 'c': compCount = atoi(optarg); break;
            case 'b': bitDepth = atoi(optarg); break;
            case 'l': dwtLvls = atoi(optarg); break;
            case 'd': device = atoi(optarg); break;
            case 'p': platform = atoi(optarg); break;
            case 'i': strcpy(input_dir, optarg); break;
            case 'f': forward = 1; break;
            case 'r': forward = 0; break;
            case '9': dwt97 = 1; break;
            case '5': dwt97 = 0; break;
            case 'w': writeVisual = 1; break;
            case 'h': usage(); return 0;
            case '?': return -1;
            default: usage(); return -1;
        }
    }
    argc -= optind;
    argv += optind;

    if (argc == 0) { printf("Please supply src file name\n"); usage(); return -1; }
    if (pixWidth <= 0 || pixHeight <= 0) { printf("Wrong or missing dimensions\n"); usage(); return -1; }
    if (forward == 0) writeVisual = 0;

    cudaSetDevice(device);

    struct dwt *d = (struct dwt *)malloc(sizeof(struct dwt));
    d->srcImg = NULL;
    d->pixWidth = pixWidth;
    d->pixHeight = pixHeight;
    d->components = compCount;
    d->dwtLvls = dwtLvls;

    d->srcFilename = (char *)malloc(strlen(argv[0]) + 1);
    strcpy(d->srcFilename, argv[0]);
    if (argc == 1) {
        d->outFilename = (char *)malloc(strlen(d->srcFilename) + 5);
        strcpy(d->outFilename, d->srcFilename);
        strcpy(d->outFilename + strlen(d->srcFilename), ".dwt");
    } else {
        d->outFilename = strdup(argv[1]);
    }

    char real_filename[100];
    sprintf(real_filename, "%s/%s", input_dir, d->srcFilename);

    printf("\nSource file:\t\t%s\n", real_filename);
    printf(" Dimensions:\t\t%dx%d\n", pixWidth, pixHeight);
    printf(" Components count:\t%d\n", compCount);
    printf(" Bit depth:\t\t%d\n", bitDepth);
    printf(" DWT levels:\t\t%d\n", dwtLvls);
    printf(" Forward transform:\t%d\n", forward);
    printf(" 9/7 transform:\t\t%d\n", dwt97);

    int inputSize = pixWidth * pixHeight * compCount;
    d->srcImg = (unsigned char *)malloc(inputSize);
    if (getImg(real_filename, d->srcImg, inputSize) == -1) return -1;

    if (forward == 1) {
        if (dwt97 == 1) processDWT<float>(d, forward, writeVisual);
        else processDWT<int>(d, forward, writeVisual);
    } else {
        if (dwt97 == 1) processDWT<float>(d, forward, writeVisual);
        else processDWT<int>(d, forward, writeVisual);
    }

    cudaDeviceSynchronize();
    free(d->srcFilename);
    free(d->outFilename);
    free(d->srcImg);
    free(d);
    return 0;
}
